setTimeout(() => {
  const modalComponent = document.querySelector(
    '[custom-css-selector="css_modal_generar_pricing"]'
  );

  if (!modalComponent || !modalComponent.__vue__) {
    return;
  }

  const vueInstance = modalComponent.__vue__;

  // ─── HELPERS CONTROL DE BOTÓN ────────────────────────────────────────────

  const tieneRequeridosVacios = () => {
    const modalEl = document.getElementById('modal_generar_pricing');
    if (!modalEl) return true;

    // 1) Campos con asterisco requerido que estén vacíos
    const requiredGroups = Array.from(
      modalEl.querySelectorAll('.form-group')
    ).filter((group) => group.querySelector('.required-asterisk'));

    const hayRequeridoVacio = requiredGroups.some((group) => {
      const input = group.querySelector('input, select, textarea');
      if (!input) return false;
      return !input.value || input.value.trim() === '';
    });

    // 2) invalid-feedback visible (con texto)
    const hayInvalidFeedback = Array.from(
      modalEl.querySelectorAll('.invalid-feedback')
    ).some((div) => {
      const style = window.getComputedStyle(div);
      const visible =
        style.display !== 'none' &&
        style.visibility !== 'hidden' &&
        style.opacity !== '0' &&
        div.offsetParent !== null;
      const tieneTexto = div.textContent.trim() !== '';
      return visible && tieneTexto;
    });

    // 3) text-invalid-in-table visible (con texto)
    const hayInvalidTable = Array.from(
      modalEl.querySelectorAll('[selector="text-invalid-in-table"]')
    ).some((div) => {
      const visible = div.offsetParent !== null;
      const tieneTexto = div.textContent.trim() !== '';
      return visible && tieneTexto;
    });

    return hayRequeridoVacio || hayInvalidFeedback || hayInvalidTable;
  };

  const actualizarEstadoBoton = () => {
    const footer = document.getElementById(
      'modal_generar_pricing___BV_modal_footer_'
    );
    if (!footer) return;

    const generarBtn = footer.querySelector('button.btn.btn-primary');
    if (!generarBtn) return;

    const hayVacios = tieneRequeridosVacios();
    generarBtn.disabled = hayVacios;
    generarBtn.classList.toggle('disabled', hayVacios);
  };

  // Referencia al intervalo para poder limpiarlo después
  let intervaloValidacion = null;

  // ─── EVENTO: MODAL ABRE ───────────────────────────────────────────────────

  vueInstance.$root.$on('bv::modal::show', (bvEvent, modalId) => {
    const modal = bvEvent.vueTarget;

    if (modalId === 'modal_generar_pricing') {

      // Esperar a que el DOM del modal esté completamente renderizado
      setTimeout(() => {
        actualizarEstadoBoton();

        if (intervaloValidacion) clearInterval(intervaloValidacion);

        intervaloValidacion = setInterval(() => {
          actualizarEstadoBoton();
        }, 500);

      }, 150);

      // ─── ON OK ───────────────────────────────────────────────────────────

      modal.onOk = () => {
        const loader = document.getElementById(
          'global-loader-overlay-generar-pricing'
        );

        const submitBtn = document.querySelector(
          'button[name="frm_decision_evaluacion_riesgo_generar_pricing"]'
        );

        // CONTROL INFORMACION COBERTURAS
        const control_ha_seleccionado_al_menos_una_cobertura =
          this.control_ha_seleccionado_al_menos_una_cobertura;

        if (control_ha_seleccionado_al_menos_una_cobertura == 'NO') {
          vueInstance.$root.$bvModal.show('modal_requiere_informacion_cobertura');
          modal.hide();
          if (loader) loader.classList.remove('show');
          return;
        }

        // CONTROL PROCEDE
        const frm_valor_asegurado_control_procede =
          this.frm_valor_asegurado_control_procede;

        if (frm_valor_asegurado_control_procede == false) {
          vueInstance.$root.$bvModal.show('modal_alert_valorAsegDeduc_alMenosUnValor');
          modal.hide();
          if (loader) loader.classList.remove('show');
          return;
        }

        // VALIDACIÓN ERRORES VISIBLES
        const erroresCustom      = document.querySelectorAll('[selector="text-invalid"]');
        const erroresCustomTable = document.querySelectorAll('[selector="text-invalid-in-table"]');
        const erroresBootstrap   = document.querySelectorAll('.invalid-feedback');
        const erroresVisibles    = [];

        erroresCustom.forEach((div) => {
          const visible = div.offsetParent !== null;
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        erroresCustomTable.forEach((div) => {
          const visible = div.offsetParent !== null;
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        erroresBootstrap.forEach((div) => {
          const visible =
            div.offsetParent !== null && div.classList.contains('d-block');
          const mensaje = div.textContent.trim().toLowerCase();
          if (visible) erroresVisibles.push(mensaje);
        });

        if (erroresVisibles.length > 0) {
          if (loader) loader.classList.remove('show');
          vueInstance.$root.$bvModal.show('modal_accion_requerida');
          modal.hide();
          return;
        }

        // SI NO HAY ERRORES → SUBMIT
        if (submitBtn) {
          submitBtn.click();
        }

        // ESPERAR Y BUSCAR ALERT
        setTimeout(() => {
          const alertError = document.querySelector(
            '.alert.alert-danger[role="alert"]'
          );

          if (alertError) {
            const texto = alertError.textContent.toLowerCase();
            if (
              texto.includes('errores de validación') ||
              texto.includes('error de validación')
            ) {
              if (loader) loader.classList.remove('show');
              vueInstance.$root.$bvModal.show('modal_accion_requerida');
              modal.hide();
              return;
            }
          }

          if (loader) loader.classList.add('show');
        }, 400);

        modal.hide();
      };
    }
  });

  // ─── EVENTO: MODAL CIERRA (limpieza de intervalo) ────────────────────────

  vueInstance.$root.$on('bv::modal::hide', (bvEvent, modalId) => {
    if (modalId === 'modal_generar_pricing') {
      if (intervaloValidacion) {
        clearInterval(intervaloValidacion);
        intervaloValidacion = null;
      }
    }
  });

}, 500);

return '';

setTimeout(() => {
  const OVERLAY_ID = "global-loader-overlay-generar-pricing";
  const TEXT_ID = "global-loader-text-generar-pricing";
  const INTERVAL_MS = 6000;
  const MENSAJES = ["Procesando...", "Generando pricing...", 
  "Procesando...", "Calculando...", 
  "Procesando...", "Generando valores...",
  "Procesando...", "Obteniendo cálculos..."
  ];

  let timer = null;
  let i = 0;
  let overlay = null;
  let textEl = null;
  let observer = null;

  const isVisible = (el) => {
    if (!el) return false;
    const cs = window.getComputedStyle(el);
    return cs.display !== "none" && cs.visibility !== "hidden" && cs.opacity !== "0";
  };

  const findOverlay = () => document.getElementById(OVERLAY_ID);

  const findTextEl = (ov) => {
    let t = document.getElementById(TEXT_ID);
    if (t) return t;

    t = ov.querySelector(`[id="${TEXT_ID}"]`)
      || ov.querySelector("[data-loader-text]")
      || ov.querySelector("div:last-child");

    return t;
  };

  const stop = () => {
    if (timer) clearInterval(timer);
    timer = null;
    i = 0;
    if (textEl) textEl.textContent = "Procesando...";
  };

  const start = () => {
    overlay = findOverlay();
    if (!overlay) return;

    textEl = findTextEl(overlay);

    if (!textEl) {
      textEl = document.createElement("div");
      textEl.id = TEXT_ID;
      textEl.style.cssText = "margin-top:10px;font-weight:bold;color:#2167ae;";
      overlay.appendChild(textEl);
    }

    if (timer) return;

    i = 0;
    textEl.textContent = MENSAJES[i];

    timer = setInterval(() => {
      if (!isVisible(overlay)) {
        stop();
        return;
      }
      i = (i + 1) % MENSAJES.length;
      textEl.textContent = MENSAJES[i];
    }, INTERVAL_MS);
  };

  const init = () => {
    overlay = findOverlay();

    if (!overlay) {
      setTimeout(init, 300);
      return;
    }

    observer = new MutationObserver(() => {
      if (overlay.classList.contains("show") && isVisible(overlay)) start();
      if (!overlay.classList.contains("show") || !isVisible(overlay)) stop();
    });

    observer.observe(overlay, { attributes: true, attributeFilter: ["class", "style"] });

    if (isVisible(overlay)) start();

    window.loaderTextRotateStart = start;
    window.loaderTextRotateStop = stop;
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => setTimeout(init, 0));
  } else {
    setTimeout(init, 0);
  }
}, 500);

